/* ── Twinkling star (emissive sphere) ── */
function Star({ pos, color, size = 0.06 }) {
  const ref = useRef();
  const phase = useRef(Math.random() * Math.PI * 2);
  useFrame(({ clock }) => {
    if (!ref.current) return;
    const brightness = 1.5 + Math.sin(clock.elapsedTime * 1.4 + phase.current) * 0.8;
    ref.current.material.emissiveIntensity = brightness;
  });
  return (
    <mesh ref={ref} position={pos}>
      <sphereGeometry args={[size, 10, 10]} />
      <meshStandardMaterial color={color} emissive={color} emissiveIntensity={1.8} roughness={0} />
    </mesh>
  );
}

/* ── Constellation line ── */
function ConstellationLine({ p1, p2, color }) {
  const points = useMemo(() => [
    new THREE.Vector3(...p1),
    new THREE.Vector3(...p2),
  ], [p1, p2]);
  return (
    <Line points={points} color={color} lineWidth={0.8} transparent opacity={0.25} />
  );
}

/* ── Ambient background stars ── */
function BgStars() {
  const geo = useMemo(() => {
    const COUNT = 500;
    const pos = new Float32Array(COUNT * 3);
    for (let i = 0; i < COUNT; i++) {
      pos[i * 3]     = (Math.random() - 0.5) * 16;
      pos[i * 3 + 1] = (Math.random() - 0.5) * 10;
      pos[i * 3 + 2] = (Math.random() - 0.5) * 5 - 2;
    }
    const g = new THREE.BufferGeometry();
    g.setAttribute("position", new THREE.BufferAttribute(pos, 3));
    return g;
  }, []);
  return (
    <points geometry={geo}>
      <pointsMaterial color="#aaaacc" size={0.012} transparent opacity={0.35} sizeAttenuation />
    </points>
  );
}

/* ── Full scene ── */
function ConstellationScene() {
  const groupRef = useRef();
  useFrame(({ clock }) => {
    if (!groupRef.current) return;
    groupRef.current.rotation.y = clock.elapsedTime * 0.055;
    groupRef.current.rotation.x = Math.sin(clock.elapsedTime * 0.07) * 0.07;
  });

  return (
    <group ref={groupRef}>
      <ambientLight intensity={0.03} />
      <BgStars />
      {CONSTELLATIONS.map((c) =>
        c.lines.map(([a, b], li) => (
          <ConstellationLine
            key={`${c.name}-${li}`}
            p1={c.stars[a].pos}
            p2={c.stars[b].pos}
            color={c.color}
          />
        ))
      )}
      {CONSTELLATIONS.map((c) =>
        c.stars.map((s, si) => (
          <Star key={`${c.name}-${si}`} pos={s.pos} color={c.color} />
        ))
      )}
    </group>
  );
}

